mapper.update:
update sys_project_defect_field
field_label = #{fieldLabel}, field_type = #{fieldType}, max_length = #{maxLength}, required = #{required}, nullable = #{nullable}, enabled = #{enabled}, sort_order = #{sortOrder}, type_config = #{typeConfig, typeHandler=com.cat2bug.system.domain.handle.JsonMapTypeHandler}, default_value = #{defaultValue, typeHandler=com.cat2bug.system.domain.handle.JsonValueTypeHandler}, update_time = #{updateTime},
where field_id = #{fieldId} and project_id = #{projectId}

update sys_project
set defect_builtin_field_config = #{config},
    update_time = #{updateTime,jdbcType=TIMESTAMP}
where project_id = #{projectId}
